Patch Set 19: Code-Review+1

/* mti_ent and mti_key must be conjoint,
        * then mti_ent::lde_name will be mti_key. */
        struct lu_dirent          mti_ent;
        char                      mti_key[NAME_MAX + 16];

Ok. This code looks error-prone because of padding on some special enviroment, but I believe it should work on current kernels and cpus.

Patch Set 21: Code-Review-1

(1 comment)

I tried the test on my local enviroment. It always passes. Even without the fix. Here is my version of the test that works (not moved to recovey-small yet.
diff --git a/lustre/include/obd_support.h b/lustre/include/obd_support.h
index 450ded7..92b59a4 100644
--- a/lustre/include/obd_support.h
+++ b/lustre/include/obd_support.h
@@ -255,6 +255,8 @@ extern char obd_jobid_var[];
 #define OBD_FAIL_MDS_RMFID_NET          0x166
 #define OBD_FAIL_MDS_STAT_DELAY                 0x167
 #define OBD_FAIL_MDS_LINKEA_DELAY       0x168
+#define OBD_FAIL_MDS_ORPHAN_CLEANUP     0x169
+#define OBD_FAIL_MDS_ORPHAN_CLEANUP_RACE 0x16a

 /* layout lock */
 #define OBD_FAIL_MDS_NO_LL_GETATTR      0x170
diff --git a/lustre/mdd/mdd_orphans.c b/lustre/mdd/mdd_orphans.c
index 0ea92e4..87a7929 100644
--- a/lustre/mdd/mdd_orphans.c
+++ b/lustre/mdd/mdd_orphans.c
@@ -324,22 +324,23 @@ static int mdd_orphan_destroy(const struct lu_env *env, struct mdd_object *obj,

        if (likely(obj->mod_count == 0)) {
                dt_write_lock(env, mdd->mdd_orphans, MOR_TGT_ORPHAN);
-               rc = dt_delete(env, mdd->mdd_orphans, key, th);
-               if (rc) {
-                       CERROR("%s: could not delete orphan "DFID": rc = %d\n",
-                              mdd2obd_dev(mdd)->obd_name, PFID(mdo2fid(obj)),
-                              rc);
-               } else if (orphan_exists) {
-                       mdo_ref_del(env, obj, th);
-                       if (S_ISDIR(mdd_object_type(obj))) {
+               if (OBD_FAIL_CHECK(OBD_FAIL_MDS_ORPHAN_CLEANUP)) {
+                       rc = -ENOENT;
+               } else {
+                       rc = dt_delete(env, mdd->mdd_orphans, key, th);
+                       rc = -ENOENT;
+               } else {
+                       rc = dt_delete(env, mdd->mdd_orphans, key, th);
+                       if (rc) {
+                               CERROR("%s: could not delete orphan "DFID": rc = %d\n",
+                                       mdd2obd_dev(mdd)->obd_name, PFID(mdo2fid(obj)),
+                                       rc);
+                       } 
+                       else if (orphan_exists) {
                                mdo_ref_del(env, obj, th);
-                               dt_ref_del(env, mdd->mdd_orphans, th);
+                               rc = mdo_destroy(env, obj, th);
+                       } else {
+                               CWARN("%s: orphan %s "DFID" doesn't exist\n",
+                                       mdd2obd_dev(mdd)->obd_name, (char *)key,
+                                       PFID(mdo2fid(obj)));
                        }
-                       rc = mdo_destroy(env, obj, th);
-               } else {
-                       CWARN("%s: orphan %s "DFID" doesn't exist\n",
-                             mdd2obd_dev(mdd)->obd_name, (char *)key,
-                             PFID(mdo2fid(obj)));
                }
                dt_write_unlock(env, mdd->mdd_orphans);
        }
diff --git a/lustre/tests/sanity.sh b/lustre/tests/sanity.sh
index ba257a3..20348e8 100755
--- a/lustre/tests/sanity.sh
+++ b/lustre/tests/sanity.sh
@@ -21169,7 +21169,7 @@ test_810() {
 }
 run_test 810 "partial page writes on ZFS (LU-11663)"

-test_811() {
+test_811a() {
        [ $(lustre_version_code $SINGLEMDS) -lt $(version_code 2.11.56) ] &&
                skip "Need MDS version at least 2.11.56"

@@ -21184,7 +21184,29 @@ test_811() {
        [[ $(do_facet mds1 pgrep orph_.*-MDD | wc -l) -eq 0 ]] ||
                error "MDD orphan cleanup thread not quit"
 }
-run_test 811 "orphan name stub can be cleaned up in startup"
+run_test 811a "orphan name stub can be cleaned up in startup"
+
+test_811b() {
+       [ $(lustre_version_code $SINGLEMDS) -lt $(version_code 2.12.00) ] &&
+               skip "Need MDS version at least 2.12.00"
+       [ $PARALLEL == "yes" ] && skip "skip parallel run"
+
+       #define OBD_FAIL_MDS_ORPHAN_DELETE      0x165
+       do_facet mds1 $LCTL set_param fail_loc=0x165
+       $MULTIOP $DIR/$tfile Ouc || error "multiop failed"
+
+       stop mds1
+
+       #define OBD_FAIL_MDS_ORPHAN_CLEANUP_RACE 0x16a
+       do_facet mdt1 $LCTL set_param fail_loc=0x0000016a
+       start mds1 $(mdsdevname 1) $MDS_MOUNT_OPTS || error "mds1 start fail"
+       sleep 5
+       #define OBD_FAIL_MDS_ORPHAN_CLEANUP     0x169
+       do_facet mds1 $LCTL set_param fail_loc=0x00000169
+       wait_update_facet mds1 "pgrep orph_.*-MDD | wc -l" "0" ||
+               error "MDD orphan cleanup thread not quit"
+}
+run_test 811b "orphan cleanup thread shouldn't be blocked even delete failed"

Patch Set 21:

To continue thread after "race" we need this patch also:
diff --git a/libcfs/libcfs/module.c b/libcfs/libcfs/module.c
index 5ad50d4..f6c00f0 100644
--- a/libcfs/libcfs/module.c
+++ b/libcfs/libcfs/module.c
@@ -245,8 +245,10 @@ static int proc_fail_loc(struct ctl_table *table, int write,
        long old_fail_loc = cfs_fail_loc;

        rc = proc_doulongvec_minmax(table, write, buffer, lenp, ppos);
-       if (old_fail_loc != cfs_fail_loc)
+       if (old_fail_loc != cfs_fail_loc) {
+               cfs_race_state = 1;
                wake_up(&cfs_race_waitq);
+       }
        return rc;
 }

